3	/// Errors produced during evaluation.
4	#[derive(Clone, Debug, PartialEq)]
5	pub enum EvalError {
6	    /// No expressions to evaluate.
7	    EmptyInput,
8	    /// Variable not found in environment.
9	    UndefinedVariable(String),
10	    /// Feature not yet implemented.
11	    Unsupported(String),
12	    /// Error from array operations.
13	    ArrayError(mlpl_array::ArrayError),
14	    /// Error from built-in function dispatch.
15	    RuntimeError(mlpl_runtime::RuntimeError),
16	}
17	
18	impl std::fmt::Display for EvalError {
19	    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
20	        match self {
21	            Self::EmptyInput => write!(f, "empty input"),
22	            Self::UndefinedVariable(name) => write!(f, "undefined variable: {name}"),
23	            Self::Unsupported(msg) => write!(f, "unsupported: {msg}"),
24	            Self::ArrayError(e) => write!(f, "array error: {e}"),
25	            Self::RuntimeError(e) => write!(f, "{e}"),
26	        }
27	    }
28	}
29	
30	impl std::error::Error for EvalError {}
31	
32	impl From<mlpl_array::ArrayError> for EvalError {
33	    fn from(e: mlpl_array::ArrayError) -> Self {
34	        Self::ArrayError(e)
35	    }
36	}
37	
38	impl From<mlpl_runtime::RuntimeError> for EvalError {
39	    fn from(e: mlpl_runtime::RuntimeError) -> Self {
40	        Self::RuntimeError(e)
41	    }
42	}
