9	/// Parse a token stream into a list of expression statements.
10	pub fn parse(tokens: &[Token]) -> Result<Vec<Expr>, ParseError> {
11	    let mut p = Parser::new(tokens);
12	    let mut stmts = Vec::new();
13	    p.skip_sep();
14	    while p.pos < p.tokens.len() && p.tokens[p.pos].kind != TokenKind::Eof {
15	        // Check for assignment: ident '=' expr
16	        let stmt = if matches!(p.tokens[p.pos].kind, TokenKind::Ident(_))
17	            && p.tokens
18	                .get(p.pos + 1)
19	                .is_some_and(|t| t.kind == TokenKind::Equals)
20	        {
21	            let name_tok = &p.tokens[p.pos];
22	            let name = match &name_tok.kind {
23	                TokenKind::Ident(n) => n.clone(),
24	                _ => unreachable!(),
25	            };
26	            let start = name_tok.span;
27	            p.pos += 2; // skip ident and '='
28	            let value = p.parse_expr(0)?;
29	            let span = Span::new(start.start, value.span().end);
30	            Expr::Assign {
31	                name,
32	                value: Box::new(value),
33	                span,
34	            }
35	        } else {
36	            p.parse_expr(0)?
37	        };
38	        stmts.push(stmt);
39	        p.skip_sep();
40	    }
41	    Ok(stmts)
42	}
43	
44	pub(crate) struct Parser<'a> {
45	    pub(crate) tokens: &'a [Token],
46	    pub(crate) pos: usize,
47	}
48	
49	impl<'a> Parser<'a> {
50	    pub(crate) fn new(tokens: &'a [Token]) -> Self {
51	        Self { tokens, pos: 0 }
52	    }
53	
54	    /// Parse an expression with precedence climbing (min_prec=0 for full expr).
55	    pub(crate) fn parse_expr(&mut self, min_prec: u8) -> Result<Expr, ParseError> {
56	        let mut lhs = self.parse_atom()?;
57	        loop {
58	            let Some((op, prec)) = self.tokens.get(self.pos).and_then(|t| match t.kind {
59	                TokenKind::Plus => Some((BinOpKind::Add, 1u8)),
60	                TokenKind::Minus => Some((BinOpKind::Sub, 1)),
61	                TokenKind::Star => Some((BinOpKind::Mul, 2)),
62	                TokenKind::Slash => Some((BinOpKind::Div, 2)),
63	                _ => None,
64	            }) else {
65	                break;
66	            };
67	            if prec < min_prec {
68	                break;
69	            }
70	            self.pos += 1;
71	            let rhs = self.parse_expr(prec + 1)?;
72	            let span = Span::new(lhs.span().start, rhs.span().end);
73	            lhs = Expr::BinOp {
74	                op,
75	                lhs: Box::new(lhs),
76	                rhs: Box::new(rhs),
77	                span,
78	            };
79	        }
80	        Ok(lhs)
81	    }
82	
83	    pub(crate) fn parse_atom(&mut self) -> Result<Expr, ParseError> {
84	        let tok = &self.tokens[self.pos];
85	        match &tok.kind {
86	            TokenKind::Minus => {
87	                let start = tok.span;
88	                self.pos += 1;
89	                let operand = self.parse_atom()?;
90	                let span = Span::new(start.start, operand.span().end);
91	                Ok(Expr::UnaryNeg {
92	                    operand: Box::new(operand),
93	                    span,
94	                })
95	            }
96	            TokenKind::IntLit(n) => {
97	                let e = Expr::IntLit(*n, tok.span);
98	                self.pos += 1;
99	                Ok(e)
100	            }
101	            TokenKind::FloatLit(f) => {
102	                let e = Expr::FloatLit(*f, tok.span);
103	                self.pos += 1;
104	                Ok(e)
105	            }
106	            TokenKind::Ident(name) => {
107	                let name = name.clone();
108	                let start = tok.span;
109	                self.pos += 1;
110	                // Function call: ident '('
111	                if self.is(TokenKind::LParen) {
112	                    self.pos += 1; // skip '('
113	                    let mut args = Vec::new();
114	                    if !self.is(TokenKind::RParen) {
115	                        args.push(self.parse_expr(0)?);
116	                        while self.is(TokenKind::Comma) {
117	                            self.pos += 1;
118	                            args.push(self.parse_expr(0)?);
119	                        }
120	                    }
121	                    if !self.is(TokenKind::RParen) {
122	                        return Err(ParseError::UnclosedDelimiter {
123	                            open: "(".into(),
124	                            span: start,
125	                        });
126	                    }
127	                    let end = self.tokens[self.pos].span;
128	                    self.pos += 1;
129	                    Ok(Expr::FnCall {
130	                        name,
131	                        args,
132	                        span: Span::new(start.start, end.end),
133	                    })
134	                } else {
135	                    Ok(Expr::Ident(name, start))
136	                }
137	            }
138	            TokenKind::LBracket => self.parse_array_lit(),
139	            TokenKind::LParen => {
140	                let open = tok.span;
141	                self.pos += 1;
142	                let expr = self.parse_expr(0)?;
143	                if !self.is(TokenKind::RParen) {
144	                    return Err(ParseError::UnclosedDelimiter {
145	                        open: "(".into(),
146	                        span: open,
147	                    });
148	                }
149	                self.pos += 1;
150	                Ok(expr)
151	            }
152	            _ => Err(ParseError::UnexpectedToken {
153	                found: format!("{:?}", tok.kind),
154	                span: tok.span,
155	            }),
156	        }
157	    }
158	
159	    fn parse_array_lit(&mut self) -> Result<Expr, ParseError> {
160	        let open_span = self.tokens[self.pos].span;
161	        self.pos += 1;
162	        let mut elems = Vec::new();
163	        if !self.is(TokenKind::RBracket) {
164	            elems.push(self.parse_expr(0)?);
165	            while self.is(TokenKind::Comma) {
166	                self.pos += 1;
167	                elems.push(self.parse_expr(0)?);
168	            }
169	        }
170	        if !self.is(TokenKind::RBracket) {
171	            return Err(ParseError::UnclosedDelimiter {
172	                open: "[".into(),
173	                span: open_span,
174	            });
175	        }
176	        let close_span = self.tokens[self.pos].span;
177	        self.pos += 1;
178	        Ok(Expr::ArrayLit(
179	            elems,
180	            Span::new(open_span.start, close_span.end),
181	        ))
182	    }
183	
184	    pub(crate) fn is(&self, kind: TokenKind) -> bool {
185	        self.pos < self.tokens.len()
186	            && std::mem::discriminant(&self.tokens[self.pos].kind) == std::mem::discriminant(&kind)
187	    }
188	
189	    pub(crate) fn skip_sep(&mut self) {
190	        while self.pos < self.tokens.len()
191	            && matches!(
192	                self.tokens[self.pos].kind,
193	                TokenKind::Newline | TokenKind::Semicolon
194	            )
195	        {
196	            self.pos += 1;
197	        }
198	    }
199	}
