fn handle_command(
    input: &str,
    tracing: &mut bool,
    last_trace: &Option<Trace>,
    env: &mut Environment,
) -> bool {
    if !input.starts_with(':') {
        return false;
    }
    match input {
        ":help" => print_help(),
        ":clear" => {
            *env = Environment::new();
            println!("Environment cleared.");
        }
        ":trace on" => {
            *tracing = true;
