        }
        ":trace off" => {
            *tracing = false;
            println!("Tracing disabled.");
        }
        ":trace json" => match last_trace {
            Some(t) => println!("{}", t.to_json()),
            None => eprintln!("No trace available. Use :trace on first."),
        },
        ":trace" => match last_trace {
            Some(t) => print_trace_summary(t),
            None => eprintln!("No trace available. Use :trace on first."),
        },
