1	//! Parser: transforms token stream into AST.
2	
3	use mlpl_core::Span;
4	
5	use crate::ast::{BinOpKind, Expr};
6	use crate::error::ParseError;
7	use crate::token::{Token, TokenKind};
8	
9	/// Parse a token stream into a list of expression statements.
10	pub fn parse(tokens: &[Token]) -> Result<Vec<Expr>, ParseError> {
11	    let mut p = Parser::new(tokens);
12	    let mut stmts = Vec::new();
13	    p.skip_sep();
14	    while p.pos < p.tokens.len() && p.tokens[p.pos].kind != TokenKind::Eof {
15	        // Check for repeat loop
16	        let stmt = if p.tokens[p.pos].kind == TokenKind::Repeat {
17	            p.parse_repeat()?
18	        } else if matches!(p.tokens[p.pos].kind, TokenKind::Ident(_))
19	            && p.tokens
20	                .get(p.pos + 1)
21	                .is_some_and(|t| t.kind == TokenKind::Equals)
22	        {
23	            let name_tok = &p.tokens[p.pos];
24	            let name = match &name_tok.kind {
25	                TokenKind::Ident(n) => n.clone(),
26	                _ => unreachable!(),
27	            };
28	            let start = name_tok.span;
29	            p.pos += 2; // skip ident and '='
30	            let value = p.parse_expr(0)?;
31	            let span = Span::new(start.start, value.span().end);
32	            Expr::Assign {
33	                name,
34	                value: Box::new(value),
35	                span,
36	            }
37	        } else {
38	            p.parse_expr(0)?
39	        };
40	        stmts.push(stmt);
41	        p.skip_sep();
42	    }
43	    Ok(stmts)
44	}
45	
46	pub(crate) struct Parser<'a> {
47	    pub(crate) tokens: &'a [Token],
48	    pub(crate) pos: usize,
49	}
50	
51	impl<'a> Parser<'a> {
52	    pub(crate) fn new(tokens: &'a [Token]) -> Self {
53	        Self { tokens, pos: 0 }
54	    }
55	
56	    /// Parse an expression with precedence climbing (min_prec=0 for full expr).
57	    pub(crate) fn parse_expr(&mut self, min_prec: u8) -> Result<Expr, ParseError> {
58	        let mut lhs = self.parse_atom()?;
59	        loop {
60	            let Some((op, prec)) = self.tokens.get(self.pos).and_then(|t| match t.kind {
61	                TokenKind::Plus => Some((BinOpKind::Add, 1u8)),
62	                TokenKind::Minus => Some((BinOpKind::Sub, 1)),
63	                TokenKind::Star => Some((BinOpKind::Mul, 2)),
64	                TokenKind::Slash => Some((BinOpKind::Div, 2)),
65	                _ => None,
66	            }) else {
67	                break;
68	            };
69	            if prec < min_prec {
70	                break;
71	            }
72	            self.pos += 1;
73	            let rhs = self.parse_expr(prec + 1)?;
74	            let span = Span::new(lhs.span().start, rhs.span().end);
75	            lhs = Expr::BinOp {
76	                op,
77	                lhs: Box::new(lhs),
78	                rhs: Box::new(rhs),
79	                span,
80	            };
81	        }
82	        Ok(lhs)
83	    }
84	
85	    pub(crate) fn parse_atom(&mut self) -> Result<Expr, ParseError> {
86	        let tok = &self.tokens[self.pos];
87	        match &tok.kind {
88	            TokenKind::Minus => {
89	                let start = tok.span;
90	                self.pos += 1;
91	                let operand = self.parse_atom()?;
92	                let span = Span::new(start.start, operand.span().end);
93	                Ok(Expr::UnaryNeg {
94	                    operand: Box::new(operand),
95	                    span,
96	                })
97	            }
98	            TokenKind::IntLit(n) => {
99	                let e = Expr::IntLit(*n, tok.span);
100	                self.pos += 1;
101	                Ok(e)
102	            }
103	            TokenKind::FloatLit(f) => {
104	                let e = Expr::FloatLit(*f, tok.span);
105	                self.pos += 1;
106	                Ok(e)
107	            }
108	            TokenKind::Ident(name) => {
109	                let name = name.clone();
110	                let start = tok.span;
111	                self.pos += 1;
112	                // Function call: ident '('
113	                if self.is(TokenKind::LParen) {
114	                    self.pos += 1; // skip '('
115	                    let mut args = Vec::new();
116	                    if !self.is(TokenKind::RParen) {
117	                        args.push(self.parse_expr(0)?);
118	                        while self.is(TokenKind::Comma) {
119	                            self.pos += 1;
120	                            args.push(self.parse_expr(0)?);
121	                        }
122	                    }
123	                    if !self.is(TokenKind::RParen) {
124	                        return Err(ParseError::UnclosedDelimiter {
125	                            open: "(".into(),
126	                            span: start,
127	                        });
128	                    }
129	                    let end = self.tokens[self.pos].span;
130	                    self.pos += 1;
131	                    Ok(Expr::FnCall {
132	                        name,
133	                        args,
134	                        span: Span::new(start.start, end.end),
135	                    })
136	                } else {
137	                    Ok(Expr::Ident(name, start))
138	                }
139	            }
140	            TokenKind::LBracket => self.parse_array_lit(),
141	            TokenKind::LParen => {
142	                let open = tok.span;
143	                self.pos += 1;
144	                let expr = self.parse_expr(0)?;
145	                if !self.is(TokenKind::RParen) {
146	                    return Err(ParseError::UnclosedDelimiter {
147	                        open: "(".into(),
148	                        span: open,
149	                    });
150	                }
151	                self.pos += 1;
152	                Ok(expr)
153	            }
154	            _ => Err(ParseError::UnexpectedToken {
155	                found: format!("{:?}", tok.kind),
156	                span: tok.span,
157	            }),
158	        }
159	    }
160	
161	    fn parse_array_lit(&mut self) -> Result<Expr, ParseError> {
162	        let open_span = self.tokens[self.pos].span;
163	        self.pos += 1;
164	        let mut elems = Vec::new();
165	        if !self.is(TokenKind::RBracket) {
166	            elems.push(self.parse_expr(0)?);
167	            while self.is(TokenKind::Comma) {
168	                self.pos += 1;
169	                elems.push(self.parse_expr(0)?);
170	            }
171	        }
172	        if !self.is(TokenKind::RBracket) {
173	            return Err(ParseError::UnclosedDelimiter {
174	                open: "[".into(),
175	                span: open_span,
176	            });
177	        }
178	        let close_span = self.tokens[self.pos].span;
179	        self.pos += 1;
180	        Ok(Expr::ArrayLit(
181	            elems,
182	            Span::new(open_span.start, close_span.end),
183	        ))
184	    }
185	
186	    fn parse_repeat(&mut self) -> Result<Expr, ParseError> {
187	        let start = self.tokens[self.pos].span;
188	        self.pos += 1; // skip 'repeat'
